static int handle_login(struct mg_connection* conn, void* cbdata) {
    char username[128], password[65];
    if (!get_param(conn, "username", username, sizeof(username)) ||
        !get_param(conn, "password", password, sizeof(password))) {
        send_json(conn, 400, "Missing parameters", NULL);
        return 200;
    }

    LoginStatus status;
    int rc = note_login(username, password, &status);

    if (rc == 0) {
        char data[256];
        snprintf(data, sizeof(data), "{\"user_id\":%d,\"username\":\"%s\"}", status.user_id, status.username);
        send_json(conn, 200, "Login successful", data);
    } else if (rc == -1) {
        send_json(conn, 401, "Invalid password", NULL);
    } else if (rc == -2) {
        send_json(conn, 403, "Account locked", NULL);
    } else if (rc == -3) {
        send_json(conn, 403, "Account locked due to too many failed attempts", NULL);
    } else {
        send_json(conn, 404, "User not found", NULL);
    }
    return 200;
}

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

int note_login(const char* username, const char* password, LoginStatus* status) {
    memset(status, 0, sizeof(*status));

    User user;
    int rc = db_user_get_by_username(username, &user);
    if (rc != 0) {
        return -1;
    }

    // 检查是否被锁定
    if (db_user_is_locked(user.id)) {
        return -2;  // 账户被锁定
    }

    // 检查密码
    if (strcmp(user.password_hash, password) != 0) {
        // 漏洞点：登录失败次数检查逻辑有缺陷
        // 前端显示3次错误锁定，但后端检查逻辑放在了错误的地方
        db_user_increment_login_fail(user.id);

        // 检查是否达到3次失败
        if (db_user_check_login_fail_limit(user.id)) {
            db_user_lock(user.id);
            return -3;  // 超过限制被锁定
        }
        return -1;  // 密码错误
    }

    // 登录成功
    db_user_reset_login_fail(user.id);

    status->is_logged_in = 1;
    status->user_id = user.id;
    strncpy(status->username, user.username, sizeof(status->username) - 1);

    return 0;
}

int db_user_get_by_username(const char* username, User* user) {
    if (g_db == NULL) return -1;

    sqlite3_stmt* stmt;
    int rc = sqlite3_prepare_v2(g_db, SELECT_USER_BY_USERNAME, -1, &stmt, NULL);
    if (rc != SQLITE_OK) return -1;

    sqlite3_bind_text(stmt, 1, username, -1, NULL);

    if (sqlite3_step(stmt) == SQLITE_ROW) {
        user->id = sqlite3_column_int(stmt, 0);
        strncpy(user->username, (const char*)sqlite3_column_text(stmt, 1), MAX_USER_LEN - 1);
        strncpy(user->password_hash, (const char*)sqlite3_column_text(stmt, 2), 64);
        user->password_hash[64] = '\0';

        if (sqlite3_column_text(stmt, 3)) {
            strncpy(user->email, (const char*)sqlite3_column_text(stmt, 3), 127);
            user->email[127] = '\0';
        } else {
            user->email[0] = '\0';
        }

        user->login_fail_count = sqlite3_column_int(stmt, 4);
        user->last_fail_time = sqlite3_column_int(stmt, 5);
        user->is_locked = sqlite3_column_int(stmt, 6);

        if (sqlite3_column_text(stmt, 7)) {
            strncpy(user->created_at, (const char*)sqlite3_column_text(stmt, 7), 31);
            user->created_at[31] = '\0';
        } else {
            user->created_at[0] = '\0';
        }

        sqlite3_finalize(stmt);
        return 0;
    }

static void send_json(struct mg_connection* conn, int status, const char* message, const char* data) {
    char reply[MAX_REPLY_LEN];
    if (data) {
        snprintf(reply, sizeof(reply),
            "{\"status\":%d,\"message\":\"%s\",\"data\":%s}",
            status, message, data);
    } else {
        snprintf(reply, sizeof(reply),
            "{\"status\":%d,\"message\":\"%s\"}",
            status, message);
    }

    mg_printf(conn, "HTTP/1.1 %d OK\r\n", status);
    mg_printf(conn, "Content-Type: application/json\r\n");
    mg_printf(conn, "Access-Control-Allow-Origin: *\r\n");
    mg_printf(conn, "Content-Length: %zu\r\n", strlen(reply));
    mg_printf(conn, "\r\n");
    mg_write(conn, reply, strlen(reply));
}
